sys_ws_operation.operation_script:
(function process( /*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
    try {
        var certificateService = new CertificateService();
        var info = certificateService.getSyncCertificatesInfo();
		if (!info) {
			certificateService.setSyncCertificatesInfo({
                status: Constants.APPLICATION_PROPERTIES.props.sync_certificates.status.processed,
                updated: null,
            });
			info = certificateService.getSyncCertificatesInfo();
		}
        if (info && info.status === Constants.APPLICATION_PROPERTIES.props.sync_certificates.status.processed) {
            gs.eventQueue(Constants.EVENT.syncCertificates, null);

            certificateService.setSyncCertificatesInfo({
                status: Constants.APPLICATION_PROPERTIES.props.sync_certificates.status.processing,
                updated: info ? info.updated : null,
            });
        }

        response.setStatus(200);
        response.setBody(info);
    } catch (error) {
        response.setStatus(500);
        response.setBody({
            error: error.message,
        });
    }
})(request, response);
